const { ethers } = require("ethers");

// Network provider (e.g., Infura, Alchemy)
const provider = new ethers.providers.JsonRpcProvider("https://mainnet.infura.io/v3/YOUR_PROJECT_ID");

// Contract ABI and address
const contractAddress = "0xYourContractAddress";
const contractABI = [{"inputs":[{"internalType":"uint256","name":"_id","type":"uint256"}],"name":"getId","outputs":[{"internalType":"string","name":"","type":"string"}],"stateMutability":"view","type":"function"},{"inputs":[{"internalType":"uint256","name":"_id","type":"uint256"}],"name":"setId","outputs":[],"stateMutability":"nonpayable","type":"function"}];

// Create contract instance
const contract = new ethers.Contract(contractAddress, contractABI, provider);

// Function to get user input and construct transaction
async function constructTransaction() {
  const idInput = document.getElementById("idInput").value;
  if (isNaN(idInput)) {
    alert("Invalid input");
    return;
  }

  // Get user's Ethereum account
  const accounts = await window.ethereum.request({ method: "eth_accounts" });
  const account = accounts[0];

  // Construct transaction
  const tx = {
    to: contractAddress,
    data: contract.interface.encodeFunctionData("getId", [idInput]),
    gasLimit: ethers.utils.hexlify(200000),
    gasPrice: ethers.utils.hexlify(20 * 10**9), // Gas price in wei (18 decimal places)
    nonce: await provider.getTransactionCount(account),
  };

  // Sign and send transaction
  try {
    const signedTx = await account.signTransaction(tx);
    const txHash = await provider.sendTransaction(signedTx.rawTransaction);
    console.log(`Transaction hash: ${txHash}`);
  } catch (error) {
    console.error(error);
  }
}

